+        className
+      )}
+    >
+      <span>{children}</span>
+      {copyable && text && (
+        <span className="absolute right-0.5 top-1/2 -translate-y-1/2">
+          <CopyButton
+            text={text}
+            variant="ghost"
+            size="sm"
+            showPreview={false}
+            className="opacity-0 group-hover:opacity-100 p-0.5"
+          />
+        </span>
+      )}
+    </span>
+  );
+}
