+
+// ============================================================================
+// Header Variant (Mobile) - 44px touch targets + swipe gestures
+// ============================================================================
+
+function HeaderProgress({
+  steps,
+  currentStep,
+  completedSteps,
+  onStepClick,
+  allowJumpAhead = false,
